1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote operation", () => {
6	    it("should price a single plain sword (enchantment 3) for a new customer's first contract as 115G (100 base * 1.1 first + 5 fee)", () => {
7	      const result = runScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [
10	          {
11	            op: "quote",
12	            items: [
13	              { type: "sword", material: "steel", enchantment: 3, cursed: false },
14	            ],
15	          },
16	        ],
17	      });
18	      expect(result).toEqual({ results: [{ premium: 115 }] });
19	    });
20	    it.todo("should price a single plain amulet for a new customer's first contract as 71G (60 base * 1.1 first + 5 fee)");
21	    it.todo("should price a single plain staff for a new customer's first contract as 93G (80 base * 1.1 first + 5 fee)");
22	    it.todo("should price a single plain potion for a new customer's first contract as 49G (40 base * 1.1 first + 5 fee)");
23	    it.todo("should price a single rune (component) for a new customer's first contract as 33G (25 base * 1.1 first = 27.5 round up 28 + 5 fee)");
24	    it.todo("should price a single moonstone (component) for a new customer's first contract as 33G (same as rune)");
25	    it.todo("should add a 50% risk surcharge for a cursed sword: 170G (100 * 1.5 * 1.1 + 5 fee)");
26	    it.todo("should add a 30% surcharge for a highly enchanted sword (enchantment=5): 148G (100 * 1.3 * 1.1 + 5 fee)");
27	    it.todo("should NOT add the highly-enchanted surcharge when enchantment=4 (boundary): sword stays at 115G");
28	    it.todo("should apply a 20% loyalty discount for a customer with yearsWithMHPCO=2: sword becomes 93G (100 * 0.8 * 1.1 + 5 fee)");
29	    it.todo("should NOT apply the loyalty discount when yearsWithMHPCO=1 (boundary): sword stays at 115G");
30	    it.todo("should apply the +10% first-insurance surcharge to the first quote (115G) and a -15% after-first discount to the second quote (90G = 100 * 0.85 + 5 fee)");
31	    it.todo("should price three runes as one building block at 60G (instead of 75G): 71G (60 * 1.1 + 5 fee)");
32	    it.todo("should price two runes individually (no block): 60G (50 * 1.1 + 5 fee)");
33	    it.todo("should price four runes as one block + one individual: 99G ((60+25) * 1.1 = 93.5 round up 94 + 5 fee)");
34	    it.todo("should price six runes as two blocks: 137G (120 * 1.1 + 5 fee)");
35	    it.todo("should NOT combine 2 runes + 1 moonstone into a block (alike = same type): 88G (75 * 1.1 = 82.5 round up 83 + 5 fee)");
36	    it.todo("should stack cursed AND highly enchanted surcharges multiplicatively on a sword: 220G (100 * 1.5 * 1.3 * 1.1 = 214.5 round up 215 + 5 fee)");
37	    it.todo("should combine cursed + highly enchanted + loyalty + first surcharges on a sword: 177G (100 * 1.5 * 1.3 * 0.8 * 1.1 = 171.6 round up 172 + 5 fee)");
38	    it.todo("should sum multiple items in a single quote then apply customer modifiers: sword + amulet for new customer first = 181G ((100+60) * 1.1 + 5 fee)");
39	    it.todo("should round UP in MHPCO's favor (non-integer): staff with loyalty + first = 76G (80 * 0.8 * 1.1 = 70.4 round up 71 + 5 fee)");
40	    it.todo("should default missing optional fields (cursed absent => false, enchantment absent => 0): plain sword first contract = 115G");
41	  });
42	
43	  describe("Claim operation", () => {
44	    it.todo("should fully reimburse damage to a dragon-material item minus the 100G deductible: dragon sword 500G damage => 400G payout");
45	    it.todo("should reimburse damage to a highly enchanted item (enchantment=8) at 50%, minus deductible: sword 500G damage => 150G payout");
46	    it.todo("should NOT reimburse damage when enchantment=7 and material is not dragon (boundary): 0G payout");
47	    it.todo("should reimburse at boundary enchantment=8: amulet 400G damage => 100G payout (200 reimbursable - 100 deductible)");
48	    it.todo("should pay 0G when item is neither dragon nor highly enchanted: amulet enchantment=2 damage 200G => 0G payout");
49	    it.todo("should fully reimburse dragon items regardless of enchantment level: dragon staff enchantment=1 damage 300G => 200G payout");
50	    it.todo("should apply a single deductible per damage event even with multiple damages: two dragon items damaged 200G each => 300G payout (400 - 100)");
51	    it.todo("should clamp payout to 0 when damage is below the deductible: dragon sword 50G damage => 0G payout");
52	    it.todo("should handle mixed eligibility within one claim: dragon sword 300G + plain amulet 200G => 200G payout (300 reimbursable - 100 deductible)");
53	    it.todo("should take the better rate when item qualifies under both rules: dragon sword enchantment=9 damage 400G => 300G payout (100% rate, not 50%)");
